// Validate index name to prevent wildcard abuse and system index access
function isValidIndexName(index) {
  if (!index || typeof index !== 'string') return false;

  // Disallow empty or whitespace-only names
  if (index.trim().length === 0) return false;

  // Disallow system/internal indices starting with '.'
  if (index.startsWith('.')) return false;

  // Allow comma-separated index names for multi-index queries
  const indices = index.split(',');
  for (const idx of indices) {
    const trimmed = idx.trim();
    if (trimmed.length === 0) return false;
    if (trimmed.startsWith('.')) return false;
    // Disallow path traversal characters
    if (/[\\\/\s<>|"?]/.test(trimmed)) return false;
    // Allow wildcards (*) but not standalone wildcard
    if (trimmed === '*') return false;
  }

  // Enforce max length
  if (index.length > 255) return false;

  return true;
}

